  /**
   * Load all ISC rules from the rules directory and build indices.
   * @returns {{ total: number, indexed: number, errors: string[] }}
   */
  loadRules() {
    const errors = [];
    const files = this._listRuleFiles();
    const rules = [];

    for (const file of files) {
