    this._buildIndex();
    this._updateMtime();
    this._loaded = true;

    // Start hot reload timer if enabled
    if (this.hotReload && !this._reloadTimer) {
      this._startHotReload();
    }

    const indexed = this.exactIndex.size + this.prefixPatterns.length +
