for(const f of fs.readdirSync('skills/isc-core/rules')){ if(!f.endsWith('.json')) continue; let j; try{j=JSON.parse(fs.readFileSync(path.join('skills/isc-core/rules',f),'utf8'))}catch{continue}
 let ev=(j.trigger||{}).events; if(ev&& !Array.isArray(ev) && typeof ev==='object') ev=Object.values(ev).flat(); ev=ev||[];
 const hits=ev.filter(x=>want.includes(x)); if(hits.length) console.log(f, hits)
}
